sql:
SELECT a.action_name, a.description, at.type_name
FROM actions a
LEFT JOIN action_types at ON a.type = at.type_id;

SELECT actions.action_name, mp_costs.mp_value
FROM actions
INNER JOIN mp_costs ON actions.mp_cost = mp_costs.mp_id;

SELECT action_name 
FROM actions 
WHERE level > 5;

external_knowledge:
- 'coming of age at level 30' refers to actions with a level of 30;
- 'tagged in the realm of PvE' corresponds to actions with the tag 'PvE';
- 'transformed MP costs' refers to the arccosine transformation of `mp_cost`;
- 'demand some energy to cast' means actions with `mp_cost` greater than 0.

- 'PvE' (Player versus Environment) refers to gameplay centered around players engaging with computer-controlled opponents;
- 'Spell' in this context refers to a magical action;
- 'Actions' are magical abilities or spells that a character can use;
- 'Acquired from' refers to the class or source from which these magical abilities or spells are learned or obtained;
- 'Arcane tomes' are metaphorical references to the database where magical actions are recorded.

sql:
SELECT action_name, description
FROM actions
WHERE action_id = 0;

SELECT actions.action_name, actions.description, classes.class_name
FROM actions
INNER JOIN classes ON actions.acquired_from = classes.class_id;

SELECT actions.action_name, action_levels.level_value
FROM actions
INNER JOIN action_levels ON actions.level = action_levels.level_id;

SELECT action_id, action_name, level
FROM actions
WHERE level > (SELECT AVG(level) FROM actions);
